ValidationRule.errorConditionFormula:
AND(
    !$Setup.leaseworks__LeaseWorksSettings__c.leaseworks__Disable_All_Triggers__c,
    NOT( 
        ISNULL(
	        leaseworks__Latest_Actual_Utilization__c  
		)
	),
	ISPICKVAL(leaseworks__Latest_Actual_Utilization__r.leaseworks__Status__c,"Approved By Lessor"),
    ISCHANGED( leaseworks__Disable_Invoice_Auto_Generation__c ) 
)
